496 |     val python = Python.getInstance()
497 |     val executor = python.getModule("executor")
498 |     
499 |     val payload = JSONObject().apply {
500 |         put("action", "chat")
501 |         put("prompt", prompt)
502 |         if (sessionId != null) put("session_id", sessionId)
503 |     }
504 |     
505 |     val raw = callConduitAction(payload)
506 | 
507 |     try {
508 |         val jsonResp = JSONObject(raw)
509 |         val candidates = jsonResp.optJSONArray("candidates") ?: return "AI Error: No candidates found."
510 |         val content = candidates.getJSONObject(0).optJSONObject("content") ?: return "AI Error: No content found."
511 |         val parts = content.optJSONArray("parts") ?: return "AI Error: No parts found."
512 |         
513 |         var finalResponse = ""
514 |         
515 |         for (i in 0 until parts.length()) {
516 |             val part = parts.getJSONObject(i)
517 |             
518 |             if (part.has("text")) {
519 |                 finalResponse += part.getString("text") + "\n"
520 |             }
521 |             
522 |             if (part.has("functionCall")) {
523 |                 val call = part.getJSONObject("functionCall")
524 |                 if (call.getString("name") == "execute_python_code") {
525 |                     val args = call.optJSONObject("args")
526 |                     val code = args?.optString("code") ?: ""
527 |                     if (code.isNotEmpty()) {
528 |                         val result = executor.callAttr("run_code", code).toString()
529 |                         finalResponse += "|||PY_RES|||$result"
530 |                     }
531 |                 }
532 |             }
533 |         }
534 |         return finalResponse.trim().ifEmpty { "AI returned an empty response." }
535 |     } catch (e: Exception) {
536 |         return "Processing Error: ${e.message}"
537 |     }
