1305 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
1306 |     function applyLocalPatch(content, ops) {
1307 |         let lines = content.split('\n');
1308 |         let logs = [];
1309 |         let success = true;
1310 | 
1311 |         if (typeof ops === 'string') {
1312 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
1313 |         }
1314 | 
1315 |         ops.forEach(op => {
1316 |             if (op.action === 'comment') return;
1317 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
1318 |             
1319 |             if (op.action === 'replace_block') {
1320 |                 // Strategy 1: Exact String Match (Fastest)
1321 |                 const currentStr = lines.join('\n');
1322 |                 if (currentStr.includes(op.find_block)) {
1323 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
1324 |                     logs.push('Exact match applied');
1325 |                     return;
1326 |                 }
1327 | 
1328 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
1329 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
1330 |                 if (searchLines.length === 0) return;
1331 | 
1332 |                 let matchStart = -1;
1333 |                 let matchEnd = -1;
1334 | 
1335 |                 // Scan file lines
1336 |                 for (let i = 0; i < lines.length; i++) {
1337 |                     // If first line matches (ignoring whitespace)
1338 |                     if (lines[i].trim() === searchLines[0]) {
1339 |                         // Check subsequent lines
1340 |                         let allMatch = true;
1341 |                         let fileOffset = 0;
1342 |                         let searchOffset = 1;
1343 |                         
1344 |                         while (searchOffset < searchLines.length) {
1345 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
1346 |                             const nextFile = lines[i + fileOffset + 1].trim();
1347 |                             // Skip empty lines in file if they aren't in search block
1348 |                             if (nextFile === '') {
1349 |                                 fileOffset++;
1350 |                                 continue;
1351 |                             }
1352 |                             if (nextFile !== searchLines[searchOffset]) {
1353 |                                 allMatch = false;
1354 |                                 break;
1355 |                             }
1356 |                             fileOffset++;
1357 |                             searchOffset++;
1358 |                         }
1359 | 
1360 |                         if (allMatch) {
1361 |                             matchStart = i;
1362 |                             matchEnd = i + fileOffset;
1363 |                             break;
1364 |                         }
1365 |                     }
1366 |                 }
1367 | 
1368 |                 if (matchStart !== -1) {
1369 |                     // Replace the range of lines
1370 |                     const replacement = op.replace_with.split('\n');
1371 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
1372 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
1373 |                 } else {
1374 |                     success = false;
1375 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
1376 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
1377 |                 }
1378 |             }
1379 |         });
1380 |         return { content: lines.join('\n'), success, logs };
1381 |     }
