3359 |     function formatBytes(bytes) {
3360 |         if (!bytes) return '0 B';
3361 |         const k = 1024;
3362 |         const sizes = ['B', 'KB', 'MB', 'GB'];
3363 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
3364 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
3365 |     }
