3367 |     function timeAgo(dateString) {
3368 |         const date = new Date(dateString);
3369 |         const now = new Date();
3370 |         const seconds = Math.floor((now - date) / 1000);
3371 |         if (seconds < 10) return 'just now';
3372 |         if (seconds < 60) return seconds + 's ago';
3373 |         const minutes = Math.floor(seconds / 60);
3374 |         if (minutes < 60) return minutes + 'm ago';
3375 |         const hours = Math.floor(minutes / 60);
3376 |         if (hours < 24) return hours + 'h ago';
3377 |         return date.toLocaleDateString();
3378 |     }
