3489 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
3490 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
3491 |         
3492 |         const navItems = document.querySelectorAll('.nav-item');
3493 |         switchTab(tabId, navItems[navIndex]);
3494 | 
3495 |         const scrollContainer = document.querySelector('.main-view');
3496 |         let retryCount = 0;
3497 |         const MAX_RETRIES = 5;
3498 | 
3499 |         const attemptNavigation = async () => {
3500 |             const element = document.querySelector(selector);
3501 |             
3502 |             if (element) {
3503 |                 console.log("[DeepJump] Element found. Scrolling...");
3504 |                 
3505 |                 // Wait for any tab transition animations
3506 |                 await new Promise(r => setTimeout(r, 300));
3507 | 
3508 |                 let offsetTop = 0;
3509 |                 let curr = element;
3510 |                 while (curr && curr !== scrollContainer) {
3511 |                     offsetTop += curr.offsetTop;
3512 |                     curr = curr.offsetParent;
3513 |                 }
3514 | 
3515 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
3516 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
3517 | 
3518 |                 // Visual Highlight
3519 |                 element.style.transition = 'all 0.5s ease';
3520 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
3521 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
3522 |                 setTimeout(() => {
3523 |                     element.style.backgroundColor = '';
3524 |                     element.style.boxShadow = '';
3525 |                 }, 3000);
3526 |                 
3527 |                 console.groupEnd();
3528 |                 return true;
3529 |             }
3530 | 
3531 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
3532 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
3533 |                 retryCount++;
3534 |                 showGlobalToast("🔍 Searching deeper...");
3535 |                 
3536 |                 await loadMoreFn(); 
3537 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
3538 |                 return attemptNavigation();
3539 |             }
3540 | 
3541 |             console.error("[DeepJump] Failed: Element not found after retries.");
3542 |             showGlobalToast("Entry not found in recent history.", true);
3543 |             console.groupEnd();
3544 |             return false;
3545 |         };
3546 | 
3547 |         setTimeout(attemptNavigation, 100);
3548 |     }
