suspend fun createNewSessionInSupabase(): String? {
    val client = OkHttpClient()
    val json = JSONObject().put("title", "New AI Conversation")
    val body = json.toString().toRequestBody("application/json".toMediaType())
    val request = Request.Builder()
        .url("https://YOUR_PROJECT_REF.supabase.co/rest/v1/conduit_sessions")
        .post(body)
        .addHeader("apikey", "YOUR_ANON_KEY")
        .addHeader("Authorization", "Bearer YOUR_ANON_KEY")
        .addHeader("Prefer", "return=representation")
        .build()

    return try {
        client.newCall(request).execute().use { response ->
            val raw = response.body?.string() ?: "[]"
            val jsonArray = org.json.JSONArray(raw)
            jsonArray.getJSONObject(0).getString("id")
        }
    } catch (e: Exception) { null }
}

suspend fun deleteSessionFromSupabase(sessionId: String): Boolean {
    val client = OkHttpClient()
    val request = Request.Builder()
        .url("https://YOUR_PROJECT_REF.supabase.co/rest/v1/conduit_sessions?id=eq.$sessionId")
        .delete()
        .addHeader("apikey", "YOUR_ANON_KEY")
        .addHeader("Authorization", "Bearer YOUR_ANON_KEY")
        .build()

    return try { client.newCall(request).execute().isSuccessful } catch (e: Exception) { false }
}

