import { serve } from "https://deno.land/std@0.168.0/http/server.ts"
import { createClient } from "https://esm.sh/@supabase/supabase-js@2"

const SYSTEM_PROMPT = `You are Conduit, a friendly AI File Manager. Use 'execute_python_code' tool for file tasks.`;

serve(async (req) => {
  const supabase = createClient(
    Deno.env.get('SUPABASE_URL') ?? '',
    Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? ''
  );

  const { action, prompt, session_id, title } = await req.json();

  // ACTION: LIST SESSIONS
  if (action === 'list_sessions') {
    const { data } = await supabase.from('conduit_sessions').select('id, title').order('created_at', { ascending: false });
    return new Response(JSON.stringify(data), { headers: { "Content-Type": "application/json" } });
  }

  // ACTION: CREATE SESSION
  if (action === 'create_session') {
    const { data } = await supabase.from('conduit_sessions').insert({ title: title || 'New AI Conversation' }).select().single();
    return new Response(JSON.stringify(data), { headers: { "Content-Type": "application/json" } });
  }

  // ACTION: DELETE SESSION
  if (action === 'delete_session') {
    await supabase.from('conduit_sessions').delete().eq('id', session_id);
    return new Response(JSON.stringify({ success: true }));
  }

  // ACTION: FETCH HISTORY
  if (action === 'fetch_history') {
    const { data } = await supabase.from('conduit_chat_history').select('sender, content').eq('session_id', session_id).order('created_at', { ascending: true });
    return new Response(JSON.stringify(data), { headers: { "Content-Type": "application/json" } });
  }

  // ACTION: CHAT (Default)
  if (action === 'chat') {
    const { data: keyData } = await supabase.from('api_keys').select('id, key').eq('service_name', 'gemini').order('usage_count', { ascending: true }).limit(1).single();
    if (!keyData) return new Response("No keys", { status: 500 });

    await supabase.from('api_keys').update({ usage_count: (keyData.usage_count || 0) + 1, last_used_at: new Date().toISOString() }).eq('id', keyData.id);
    await supabase.from('conduit_chat_history').insert({ session_id, sender: 'user', content: prompt });

    const response = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/gemini-3-flash-preview:generateContent?key=${keyData.key}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        contents: [{ parts: [{ text: prompt }] }],
        system_instruction: { parts: [{ text: SYSTEM_PROMPT }] },
        tools: [{ function_declarations: [{ name: "execute_python_code", parameters: { type: "object", properties: { code: { type: "string" } } } }] }]
      })
    });

    const result = await response.json();
    const aiText = result.candidates?.[0]?.content?.parts?.[0]?.text || "Executed logic.";
    await supabase.from('conduit_chat_history').insert({ session_id, sender: 'ai', content: aiText });

    return new Response(JSON.stringify(result), { headers: { "Content-Type": "application/json" } });
  }

  return new Response("Invalid Action", { status: 400 });
})

