1854 |      * it attempts to double-escape backslashes that aren't valid JSON control chars.
1855 |      */
1856 |     function smartJSONParse(jsonString) {
1857 |         try {
1858 |             return JSON.parse(jsonString);
1859 |         } catch (e) {
1860 |             console.warn("Standard JSON parse failed, attempting Robust Auto-Fix...");
1861 |             let fixed = jsonString
1862 |                 // 1. Fix backslashes that aren't part of a valid escape sequence
1863 |                 .replace(/\\(?!["\\/bfnrtu])/g, "\\\\")
1864 |                 // 2. Fix literal newlines inside strings (replace with \n)
1865 |                 .replace(/(\n)/g, (match, p1, offset) => {
1866 |                     // Only replace if we are likely inside a quoted string
1867 |                     const before = jsonString.slice(0, offset);
1868 |                     const quoteCount = (before.match(/"/g) || []).length;
1869 |                     return (quoteCount % 2 === 1) ? "\\n" : "\n";
1870 |                 });
1871 | 
1872 |             try {
1873 |                 const cleanObj = JSON.parse(fixed);
1874 |                 document.getElementById('json-input').value = fixed;
1875 |                 if (typeof saveState === 'function') saveState();
1876 |                 showGlobalToast("✨ Robust Auto-Correction Applied");
1877 |                 return cleanObj;
1878 |             } catch (e2) {
1879 |                 console.error("Robust fix failed:", e2);
1880 |                 throw e; // Throw original error for better debugging
1881 |             }
1882 |         }
1883 |     }
