2103 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2104 |     function applyLocalPatch(content, ops) {
2105 |         let lines = content.split('\n');
2106 |         let logs = [];
2107 |         let success = true;
2108 | 
2109 |         if (typeof ops === 'string') {
2110 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2111 |         }
2112 | 
2113 |         ops.forEach(op => {
2114 |             if (op.action === 'comment') return;
2115 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2116 |             
2117 |             if (op.action === 'replace_block') {
2118 |                 // Strategy 1: Exact String Match (Fastest)
2119 |                 const currentStr = lines.join('\n');
2120 |                 if (currentStr.includes(op.find_block)) {
2121 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2122 |                     logs.push('Exact match applied');
2123 |                     return;
2124 |                 }
2125 | 
2126 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2127 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2128 |                 if (searchLines.length === 0) return;
2129 | 
2130 |                 let matchStart = -1;
2131 |                 let matchEnd = -1;
2132 | 
2133 |                 // Scan file lines
2134 |                 for (let i = 0; i < lines.length; i++) {
2135 |                     // If first line matches (ignoring whitespace)
2136 |                     if (lines[i].trim() === searchLines[0]) {
2137 |                         // Check subsequent lines
2138 |                         let allMatch = true;
2139 |                         let fileOffset = 0;
2140 |                         let searchOffset = 1;
2141 |                         
2142 |                         while (searchOffset < searchLines.length) {
2143 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2144 |                             const nextFile = lines[i + fileOffset + 1].trim();
2145 |                             // Skip empty lines in file if they aren't in search block
2146 |                             if (nextFile === '') {
2147 |                                 fileOffset++;
2148 |                                 continue;
2149 |                             }
2150 |                             if (nextFile !== searchLines[searchOffset]) {
2151 |                                 allMatch = false;
2152 |                                 break;
2153 |                             }
2154 |                             fileOffset++;
2155 |                             searchOffset++;
2156 |                         }
2157 | 
2158 |                         if (allMatch) {
2159 |                             matchStart = i;
2160 |                             matchEnd = i + fileOffset;
2161 |                             break;
2162 |                         }
2163 |                     }
2164 |                 }
2165 | 
2166 |                 if (matchStart !== -1) {
2167 |                     // Replace the range of lines
2168 |                     const replacement = op.replace_with.split('\n');
2169 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2170 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2171 |                 } else {
2172 |                     success = false;
2173 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2174 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2175 |                 }
2176 |             }
2177 |         });
2178 |         return { content: lines.join('\n'), success, logs };
2179 |     }
