2207 |                 const data = await res.json();
2208 |                 const ops = data.operations;
2209 | 
2210 |                 if (!ops || ops === "[]") throw new Error("AI could not generate a fix.");
2211 | 
2212 |                 // 2. Apply Patch Locally
