2230 |                     // If errors remain, update list and Prompt user
2231 |                     currentErrors = scanData.errors;
2232 |                     if (confirm(`Fix applied, but ${currentErrors.length} errors remain. Continue fixing?`)) {
2233 |                         // Recursively fix the *new* first error (since layout changed)
2234 |                         return await fixNext(0);
2235 |                     } else {
2236 |                         return false;
2237 |                     }
2238 |                 }
2239 | 
2240 |             } catch (e) {
2241 |                 if (confirm(`Auto-Fix Failed: ${e.message}\n\nTry again?`)) {
2242 |                     return await fixNext(index);
2243 |                 } else {
2244 |                     return false;
2245 |                 }
2246 |             }
2247 |         }
2248 | 
2249 |         return await fixNext(0);
