4912 |     function formatBytes(bytes) {
4913 |         if (!bytes) return '0 B';
4914 |         const k = 1024;
4915 |         const sizes = ['B', 'KB', 'MB', 'GB'];
4916 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
4917 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
4918 |     }
