4920 |     function timeAgo(dateString) {
4921 |         const date = new Date(dateString);
4922 |         const now = new Date();
4923 |         const seconds = Math.floor((now - date) / 1000);
4924 |         if (seconds < 10) return 'just now';
4925 |         if (seconds < 60) return seconds + 's ago';
4926 |         const minutes = Math.floor(seconds / 60);
4927 |         if (minutes < 60) return minutes + 'm ago';
4928 |         const hours = Math.floor(minutes / 60);
4929 |         if (hours < 24) return hours + 'h ago';
4930 |         return date.toLocaleDateString();
4931 |     }
