5139 | 
5140 |         const attemptNavigation = async () => {
5141 |             const element = document.querySelector(selector);
5142 |             
5143 |             if (element) {
5144 |                 console.log("[DeepJump] Element found. Scrolling...");
5145 |                 
5146 |                 // Wait for any tab transition animations
5147 |                 await new Promise(r => setTimeout(r, 300));
5148 | 
5149 |                 let offsetTop = 0;
5150 |                 let curr = element;
5151 |                 while (curr && curr !== scrollContainer) {
5152 |                     offsetTop += curr.offsetTop;
5153 |                     curr = curr.offsetParent;
5154 |                 }
5155 | 
5156 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5157 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5158 | 
