5170 |             }
5171 | 
5172 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5173 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5174 |                 retryCount++;
5175 |                 showGlobalToast("🔍 Searching deeper...");
5176 |                 
5177 |                 await loadMoreFn(); 
5178 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5179 |                 return attemptNavigation();
5180 |             }
5181 | 
5182 |             console.error("[DeepJump] Failed: Element not found after retries.");
5183 |             showGlobalToast("Entry not found in recent history.", true);
5184 |             console.groupEnd();
5185 |             return false;
5186 |         };
