6475 | 
6476 |         const idsToDelete = checkboxes.map(cb => cb.value);
6477 |         
6478 |         // Find the oldest record among the selection to determine rollback target
6479 |         // dbHistory is sorted newest -> oldest
6480 |         let oldestSelectedIndex = -1;
6481 |         checkboxes.forEach(cb => {
6482 |             const idx = dbHistory.findIndex(h => String(h.id) === String(cb.value));
6483 |             if (idx > oldestSelectedIndex) oldestSelectedIndex = idx;
6484 |         });
6485 | 
6486 |         // The target is the first record older than our selection that isn't also being deleted
6487 |         let rollbackTarget = null;
6488 |         for (let i = oldestSelectedIndex + 1; i < dbHistory.length; i++) {
6489 |             if (!idsToDelete.includes(String(dbHistory[i].id))) {
6490 |                 rollbackTarget = dbHistory[i];
6491 |                 break;
6492 |             }
6493 |         }
