7288 |     function extractTableNames(sql) {
7289 |         if (!sql) return [];
7290 |         const tables = [];
7291 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7292 |         
7293 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7294 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7295 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7296 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7297 | 
7298 |         let match;
7299 |         while ((match = fromRegex.exec(sql)) !== null) {
7300 |             const name = match[1];
7301 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7302 |                 tables.push(name);
7303 |             }
7304 |         }
7305 |         
7306 |         while ((match = metaRegex.exec(sql)) !== null) {
7307 |             const name = match[1];
7308 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7309 |                 tables.push(name);
7310 |             }
7311 |         }
7312 | 
7313 |         return tables;
7314 |     }
