7316 |     function convertToCSV(resultObj) {
7317 |         const data = resultObj.data || [];
7318 |         if (!data.length) return '';
7319 |         
7320 |         const tables = extractTableNames(resultObj.sql);
7321 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7322 | 
7323 |         const headers = Object.keys(data[0]);
7324 |         const rows = data.map(row => 
7325 |             headers.map(header => {
7326 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7327 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7328 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7329 |             }).join(',')
7330 |         );
7331 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7332 |     }
