};

window.copyActiveHudData = () => {
    const isConsole = window.activeHudTab === 'console';
    const data = isConsole ? window.localLogs : window.localNetLogs;
    const text = data.map(i => isConsole ? `[${i.time}] ${i.msg}` : `[${i.time}] ${i.method} ${i.status} ${i.url}`).join('\n');
    navigator.clipboard.writeText(text).then(() => alert("Copied all " + window.activeHudTab + " logs!"));
};

window.clearHudData = () => {
    if(window.activeHudTab === 'console') window.localLogs = [];
    else window.localNetLogs = [];
    window.updateLocalLogUI();
};

window.updateLocalLogUI = () => {
    if (window.activeHudTab === 'console') {
        list.innerHTML = window.localLogs.map((l, idx) => `
