            min-height: 250px; margin-bottom: 12px;
        }

        /* TERMINAL / LOGS */
        .terminal-container { 
            display: flex; flex-direction: column; gap: 10px; 
            /* Removed internal scrolling to allow page scrolling */
            margin-bottom: 20px;
        }

        /* Markdown Styles for AI Chat */
        .msg-ai p { margin: 0 0 8px 0; } .msg-ai p:last-child { margin: 0; }
        .msg-ai ul, .msg-ai ol { margin: 0 0 8px 0; padding-left: 20px; }
        .msg-ai code { background: rgba(255,255,255,0.1); padding: 2px 4px; border-radius: 4px; font-family: 'JetBrains Mono', monospace; font-size: 11px; }
        .msg-ai pre code { background: none; padding: 0; }
        .terminal-label { font-size: 12px; text-transform: uppercase; color: var(--text-muted); letter-spacing: 1px; margin-bottom: 5px; flex-shrink: 0; }

        .log-entry {
            border: 1px solid var(--border); border-radius: 8px; /* overflow: hidden; <-- REMOVED */
