        .status-pill { padding: 2px 6px; border-radius: 4px; font-size: 10px; font-weight: bold; text-transform: uppercase; }
        .pill-success { background: rgba(34, 197, 94, 0.2); color: var(--prod); }
        .pill-fail { background: rgba(239, 68, 68, 0.2); color: var(--danger); }
        .log-body { display: none; padding: 0; }
        .log-body.open { display: block; }

        .op-row {
            padding: 10px 12px; border-bottom: 1px solid #222; font-size: 11px;
