        .msg-ai { align-self: flex-start; background: #222; color: #ddd; border: 1px solid #333; border-bottom-left-radius: 2px; }

        .msg-wrapper { display: flex; flex-direction: column; width: 100%; position: relative; }
        .msg:hover .msg-actions { opacity: 1; }
        .msg-actions { 
            position: absolute; bottom: -20px; right: 0; 
            opacity: 0; transition: opacity 0.2s; 
            display: flex; gap: 4px; background: #111; padding: 2px; border-radius: 4px; border: 1px solid #333;
        }
        .msg-ai .msg-actions { right: auto; left: 0; }
        .action-mini-btn { 
            background: none; border: none; color: #888; cursor: pointer; padding: 2px 4px; font-size: 10px; 
        }
        .action-mini-btn:hover { color: white; }

        /* Code blocks in chat */
        .msg-ai pre { background: #111; padding: 8px; border-radius: 6px; overflow-x: auto; margin-top: 8px; font-family: 'JetBrains Mono', monospace; font-size: 11px; }

        .chat-input-area {
            padding: 12px; background: #0a0a0a; border-top: 1px solid var(--border);
            display: flex; gap: 8px; padding-bottom: 30px; /* Safe area */
        }
        .chat-input {
            flex: 1; background: #1a1a1c; border: 1px solid #333; color: white;
            padding: 10px; border-radius: 20px; outline: none; font-size: 13px;
        }
        .chat-input:focus { border-color: var(--ai-accent); }

/* Chat History Styles */
        .chat-history-overlay {
            position: absolute; top: 60px; left: 0; width: 100%; height: calc(100% - 60px);
            background: #151517; z-index: 10; display: none;
            flex-direction: column; padding: 10px; overflow-y: auto;
        }
        .chat-history-overlay.active { display: flex; animation: fadeUp 0.2s; }

        .history-item {
            padding: 14px; border-bottom: 1px solid var(--border);
            cursor: pointer; display: flex; justify-content: space-between; align-items: center;
        }
        .history-item:hover { background: #1e1e20; }
        .history-title { font-size: 13px; font-weight: 500; color: #eee; }
