        /* Header Icons Gap */
        .chat-header .flex-gap .icon-btn { border: none; background: transparent; padding: 6px; }
        .chat-header .flex-gap .icon-btn:hover { background: rgba(255,255,255,0.1); }

        /* AI SETTINGS UI */
        .ai-section-title { font-size: 12px; font-weight: 600; color: var(--ai-accent); margin: 20px 0 10px 0; text-transform: uppercase; letter-spacing: 0.5px; }
        .ai-provider-card { background: #1a1a1c; border: 1px solid var(--border); border-radius: 8px; padding: 12px; margin-bottom: 10px; position: relative; }
