    // --- CORE UTILS ---
    /**
     * Tries to parse JSON. If it fails due to bad escaping (common with AI),
     * it attempts to double-escape backslashes that aren't valid JSON control chars.
     */
    function smartJSONParse(jsonString) {
        try {
            return JSON.parse(jsonString);
        } catch (e) {
            console.warn("Standard JSON parse failed, attempting Robust Auto-Fix...");
            let fixed = jsonString
                // 1. Fix backslashes that aren't part of a valid escape sequence
                .replace(/\\(?!["\\/bfnrtu])/g, "\\\\")
                // 2. Fix literal newlines inside strings (replace with \n)
                .replace(/(\n)/g, (match, p1, offset) => {
                    // Only replace if we are likely inside a quoted string
                    const before = jsonString.slice(0, offset);
                    const quoteCount = (before.match(/"/g) || []).length;
                    return (quoteCount % 2 === 1) ? "\\n" : "\n";
                });

            try {
                const cleanObj = JSON.parse(fixed);
                document.getElementById('json-input').value = fixed;
                if (typeof saveState === 'function') saveState();
                showGlobalToast("✨ Robust Auto-Correction Applied");
                return cleanObj;
            } catch (e2) {
                console.error("Robust fix failed:", e2);
                throw e; // Throw original error for better debugging
            }
        }
    }

    function b64DecodeUnicode(str) {
        return decodeURIComponent(atob(str).split('').map(function(c) {
            return '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2);
        }).join(''));
    }

    // Unicode-Safe Encoder for AI Context
    function b64EncodeUnicode(str) {
        return btoa(encodeURIComponent(str).replace(/%([0-9A-F]{2})/g,
            function toSolidBytes(match, p1) { return String.fromCharCode('0x' + p1); }));
    }

    function apiBody(obj) {
