            sidebar.innerHTML = '';
            if (functions.size === 0) {
                sidebar.innerHTML = '<div style="padding:20px; color:#666; font-size:11px; text-align:center;">No functions found in /supabase/functions/</div>';
                status.innerText = "Scan complete: 0 found.";
