// --- CHAT SESSION MANAGEMENT ---
    let currentChatId = null;

    function startNewChat() {
        currentChatId = null;
        chatHistory = [];
        const container = document.getElementById('chat-messages');
        container.innerHTML = `<div class="msg msg-ai">Started a new session. How can I help?</div>`;
        document.getElementById('chat-history-list').classList.remove('active');
    }

    async function toggleChatHistory() {
        const list = document.getElementById('chat-history-list');
        if (list.classList.contains('active')) {
            list.classList.remove('active');
            return;
        }

        list.classList.add('active');
        list.innerHTML = '<div style="text-align:center; padding:20px; color:#666;">Fetching history...</div>';

        try {
            const res = await fetch(CONFIG.funcUrl, {
                method: 'POST', headers: {'Content-Type': 'application/json'},
                body: apiBody({ action: 'fetch_chats' })
            });
            const data = await res.json();

            if (!data.chats || data.chats.length === 0) {
                list.innerHTML = '<div style="text-align:center; padding:20px; color:#666;">No past conversations.</div>';
                return;
            }

            list.innerHTML = data.chats.map(chat => `
                <div class="history-item" onclick="loadChatSession('${chat.id}')">
                    <div class="history-title">${chat.title}</div>
                    <div class="history-date">${new Date(chat.created_at).toLocaleDateString()}</div>
                </div>
            `).join('');

        } catch (e) {
            list.innerHTML = `<div style="text-align:center; color:var(--danger);">Error: ${e.message}</div>`;
        }
    }

    async function loadChatSession(id) {
        document.getElementById('chat-history-list').classList.remove('active');
        currentChatId = id;
        document.getElementById('chat-messages').innerHTML = '<div style="text-align:center; padding:20px; color:#666;">Restoring chat...</div>';

        try {
            const res = await fetch(CONFIG.funcUrl, {
                method: 'POST', headers: {'Content-Type': 'application/json'},
                body: apiBody({ action: 'load_chat', chat_id: id })
            });
            const data = await res.json();

            chatHistory = data.messages || [];
            const container = document.getElementById('chat-messages');
            container.innerHTML = '';

            renderChatFromHistory();
            container.scrollTop = container.scrollHeight;

        } catch (e) {
            alert("Failed to load chat: " + e.message);
        }
    }

    // --- GLOBAL SEARCH ---
    async function runGlobalSearch() {
        const query = document.getElementById('global-search-input').value.trim();
        if (!query) return;
        const list = document.getElementById('search-results-list');
        list.innerHTML = '<div style="padding:20px; text-align:center; color:var(--ai-accent);">Scanning project...</div>';

        try {
            const res = await fetch(CONFIG.funcUrl, {
                method: 'POST', headers: { 'Content-Type': 'application/json' },
                body: apiBody({ action: 'search_repo', query: query, project_path: CONFIG.projectPath })
            });
            const data = await res.json();
            if (!data.results || data.results.length === 0) {
                list.innerHTML = '<div style="padding:20px; text-align:center; color:#666;">No results found.</div>';
                return;
            }
            list.innerHTML = data.results.map(r => `
