        async function loadWorkflows(silent = false, isAppend = false) {
        const container = document.getElementById('workflow-list');
        if (!isAppend) workflowPage = 1;

        if (!silent && !isAppend && container.children.length === 0) {
            container.innerHTML = '<div style="padding:20px; text-align:center;">Fetching runs...</div>';
        }

        try {
            const res = await fetch(CONFIG.funcUrl, { 
                method: 'POST', headers: {'Content-Type': 'application/json'}, 
                body: apiBody({ action: 'fetch_workflows', page: workflowPage }) 
            });
            lastCicdRefresh = Date.now(); 
            const data = await res.json();

            if (data.runs && data.runs.length < 20) document.getElementById('load-more-cicd-btn').style.display = 'none';
            else document.getElementById('load-more-cicd-btn').style.display = 'block';

            // --- SMART POLLING LOGIC ---
            // 1. Check if we are still on the tab
            const isTabActive = document.getElementById('tab-cicd').classList.contains('active');

            // 2. Check if any runs are active
            const hasActiveRuns = data.runs && data.runs.some(r => r.status === 'in_progress' || r.status === 'queued');

            // 3. Schedule next poll ONLY if needed
            if (isTabActive && hasActiveRuns) {
                setTimeout(() => loadWorkflows(true), 10000);
            }
            // ---------------------------

            // --- AUTOMATION LOOP ---
            if (CONFIG.autoFix && data.runs && data.runs.length > 0) {
                const latest = data.runs[0];
                const fixedKey = 'conduit_fixed_' + latest.id;

                // RECURSION GUARD: Check if the failed commit was already an Auto-Fix
                const isRecursion = latest.head_commit && latest.head_commit.message.includes("[Auto-Fix]");

                if (latest.conclusion === 'failure' && !localStorage.getItem(fixedKey) && !isRecursion) {
                    const toast = document.createElement('div');
                    toast.innerHTML = `<span style="animation:pulse 1s infinite">🤖 Auto-Fixing Run #${latest.run_number}...</span>`;
                    toast.style.cssText = "position:fixed; bottom:150px; left:50%; transform:translateX(-50%); background:#eab308; color:black; padding:10px 20px; border-radius:30px; z-index:9999; font-weight:bold;";
                    document.body.appendChild(toast);

                    localStorage.setItem(fixedKey, 'true');

                    fetch(CONFIG.funcUrl, {
                        method: 'POST', headers: {'Content-Type': 'application/json'},
                        body: apiBody({ action: 'auto_fix_build', run_id: latest.id })
                    }).then(r => r.json()).then(d => {
                        toast.remove();
                        if(d.success) {
                            alert(`🤖 Auto-Fix Applied!\n\nAI successfully generated and committed a patch.`);
                            loadWorkflows(); 
                        }
                    });
                }
            }

            if(!data.runs || data.runs.length === 0) {
                if (!silent && !isAppend) container.innerHTML = '<div style="padding:20px; text-align:center;">No workflow runs found.</div>';
                return;
            }

            const expandedIds = Array.from(container.querySelectorAll('div[id^="wf-jobs-"]'))
