    async function downloadSingleFile(path, btn) {
        const originalHtml = btn.innerHTML;
        btn.innerHTML = '⏳'; // Visual feedback
        btn.disabled = true;
        btn.style.opacity = '0.7';

        try {
            const res = await fetch(CONFIG.funcUrl, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: apiBody({ action: 'preview_file', file_path: path })
            });
            const data = await res.json();
            if(!data.content) throw new Error("No content found");

            const blob = new Blob([b64DecodeUnicode(data.content)], { type: "application/octet-stream" });
            const link = document.createElement('a');
            link.href = URL.createObjectURL(blob);
            link.download = path.split('/').pop();
            link.click();
        } catch(e) { 
            alert("Download failed: " + e.message); 
        } finally {
            btn.innerHTML = originalHtml;
            btn.disabled = false;
            btn.style.opacity = '1';
        }
    }

