            const now = Date.now();
            const hasActiveRuns = Object.values(runStateCache).some(s => s === 'in_progress' || s === 'queued');
            // Fetch if: Never fetched OR >60s ago OR active runs exist
            if (lastCicdRefresh === 0 || (now - lastCicdRefresh > 60000) || hasActiveRuns) {
                loadWorkflows(false);
