    function fixPreviewError(msg) {
        console.group("[SurgicalDebug] Initializing...");
        startNewChat();
        toggleChat(true);

        // 1. Extract Filename using Regex (matches path.js:line:col or path.js)
        const fileMatch = msg.match(/([\w.-]+\.(?:js|html|css|ts|tsx|jsx))/i);
        const filePath = fileMatch ? fileMatch[1] : null;

        let surgicalContext = null;

        // 2. Resolve Full Path and Operation History
        if (filePath) {
            // Find actual path in cache (handling partial matches from console)
            const fullPath = Object.keys(window.CURRENT_FILE_CACHE || {}).find(p => p.endsWith(filePath));
            if (fullPath) {
                const lastOps = FILE_OP_MAP[fullPath] || [];
                surgicalContext = {
                    path: fullPath,
                    content: window.CURRENT_FILE_CACHE[fullPath].content,
                    lastOp: lastOps[lastOps.length - 1] || "No recent op recorded for this file.",
                    error: msg
                };
                console.log("[SurgicalDebug] Context found for:", fullPath);
            }
        }

        if (surgicalContext) {
            window.SURGICAL_DEBUG_DATA = surgicalContext;
            const prompt = `[SURGICAL DEBUG]\nFILE: ${surgicalContext.path}\nERROR: ${surgicalContext.error}\n\nLAST OPERATION APPLIED TO THIS FILE:\n${JSON.stringify(surgicalContext.lastOp, null, 2)}\n\nAnalyze the regression caused by this specific operation and provide a fix.`;
            chatHistory.push({ role: 'user', text: prompt });
        } else {
            console.warn("[SurgicalDebug] No specific file context identified. Falling back to global context.");
            chatHistory.push({ role: 'user', text: `My application logged a runtime error: "${msg}". Analyze my selected files and suggest a fix.` });
        }

        processAIResponse();
        console.groupEnd();
    }

