    }

    if (action === "fetch_workflows") {
      const data = await githubFetch(TARGET_REPO, `/actions/runs?per_page=50`);
      return new Response(JSON.stringify({ runs: data.workflow_runs }), { headers: { ...corsHeaders, "Content-Type": "application/json" } });
