      const aiData = await aiRes.json();
      const analysis = aiData.choices?.[0]?.message?.content || "Failed.";
      await supabase.from('conduit_logs').insert({ repo_name: TARGET_REPO, type: 'job_analysis', data: { job_id: String(job_id), analysis } });
