        const tree = await githubFetch(TARGET_REPO, `/git/trees/${DEV_BRANCH}?recursive=1`);
        const files = tree.tree.filter((f: any) => f.type === "blob" && f.path.startsWith(scopePath));
        let copiedCount = 0;
        for (const file of files) {
