    const prompt = `
    I just performed a code modification. Check if it introduced any FATAL syntax errors.

    OPERATION PERFORMED:
    ${JSON.stringify(op, null, 2)}

    RESULTING FILE CONTENT:
    ${code.substring(0, 15000)}

