        localStorage.setItem('conduit_ef_mode', efDeploymentMode);

        // Save AI Config
        localStorage.setItem('conduit_ai_config', JSON.stringify(window.aiConfig));

        CONFIG = { funcUrl, repoName, projectPath, autoFix, autoSanity, showPreview, wasmValidation, efDeploymentMode };

        applyPreviewTabVisibility(); // Apply change immediately

        alert("Settings Saved!");

        // Reset UI
        document.getElementById('file-list-container').innerHTML = '';
        document.getElementById('history-container').innerHTML = '';
        document.getElementById('terminal-list').innerHTML = '';
        document.getElementById('preview-frame').srcdoc = '';

