    function updateChatContextIndicator() {
        const bar = document.getElementById('chat-context-bar');
        if (!bar) return;
        bar.innerHTML = '';

        if (window.SURGICAL_DEBUG_DATA) {
            const pill = document.createElement('div');
            pill.className = 'context-pill surgical';
            pill.innerHTML = `<span>🎯 DEBUG: ${window.SURGICAL_DEBUG_DATA.path.split('/').pop()}</span>`;
            bar.appendChild(pill);
            return;
        }

        const checked = Array.from(document.querySelectorAll('#file-list-container .file-check:checked'));

        if (checked.length === 0) {
            bar.innerHTML = '<span style="font-size:10px; color:#444; padding:4px;">No files attached</span>';
            return;
        }

        // Show first 5 files as pills
        checked.slice(0, 5).forEach(cb => {
