        else if (options.error) div.innerHTML = `<div class="log-header" style="color:var(--danger)"><span>Error</span></div><div class="log-body open" style="padding:12px; color:var(--danger); font-size:11px; overflow-wrap:anywhere;">${escapeHtml(options.error)}</div>`;

        container.prepend(div);
