    // New helper function to toggle our terminal menus
    function toggleLogMenu(id, event) {
        event.stopPropagation(); // Prevent the log body from toggling
        const menu = document.getElementById(id + '-menu');
        // Close all other menus first
        document.querySelectorAll('.log-header .menu-dropdown').forEach(m => {
