    // --- STAGING ---
    let pendingOps = [];
    async function stageChanges() {
        const input = document.getElementById('json-input').value;
        try {
            const payload = smartJSONParse(input);
            pendingOps = Array.isArray(payload) ? payload : (payload.operations || []);
            if (pendingOps.length === 0) return alert("No operations to stage.");

            renderStagingUI();
            document.getElementById('staging-overlay').classList.add('active');
        } catch(e) { alert("JSON Error: " + e.message); }
    }

    function renderStagingUI() {
        const list = document.getElementById('staging-list');
        if (!list) return;
        list.innerHTML = '';

        pendingOps.forEach((op, i) => {
            if (op.action === 'comment') return;
            const div = document.createElement('div');
            div.className = 'stage-item';
            div.innerHTML = `
                <div class="stage-header" onclick="previewStageDiff(${i})">
                    <span style="color:var(--ai-accent); font-weight:bold; flex-shrink:0;">${op.action === 'replace_block' ? 'MOD' : (op.action === 'create_file' ? 'ADD' : 'DEL')}</span>
                    <span class="stage-path">${op.file_path}</span>
                    <button class="menu-btn" style="color:var(--danger); flex-shrink:0; padding: 4px 8px; font-size: 16px;" onclick="event.stopPropagation(); removeStagedOp(${i})">×</button>
                </div>
            `;
            list.appendChild(div);
        });
    }

    function removeStagedOp(i) {
        pendingOps.splice(i, 1);
        // Sync back to editor so state is preserved
        document.getElementById('json-input').value = JSON.stringify(pendingOps, null, 2);
        saveState();
        renderStagingUI();
    }

    async function previewStageDiff(i) {
        const op = pendingOps[i];
        showGlobalToast("Generating preview...");

        try {
            // 1. Fetch current content (Left side)
            const res = await fetch(CONFIG.funcUrl, {
                method: 'POST', headers: {'Content-Type': 'application/json'},
                body: apiBody({ action: 'preview_file', file_path: op.file_path })
            });
            const data = await res.json();
            const currentContent = data.content ? b64DecodeUnicode(data.content) : "";

            // 2. Simulate the patch locally (Right side)
            const patchResult = applyLocalPatch(currentContent, [op]);

            // 3. Open viewer with simulated data
            const mockId = 'staged-' + i;
            window.OP_CACHE[mockId] = { file: op.file_path, op: op, commit_sha: 'STAGED' };
            openDiffViewer(mockId, currentContent, patchResult.content);
        } catch (e) {
            showGlobalToast("Failed to generate diff: " + e.message, true);
        }
    }

