        const toast = document.createElement('div'); toast.innerText = "📄 Fetching Summary..."; toast.style.cssText = "position:fixed; bottom:100px; left:50%; transform:translateX(-50%); background:#333; color:white; padding:10px 20px; border-radius:30px; z-index:9999;"; document.body.appendChild(toast);
        try {
            const res = await fetch(CONFIG.funcUrl, { method: 'POST', headers: {'Content-Type': 'application/json'}, body: apiBody({ action: 'analyze_log', job_id: id }) });
            const data = await res.json();
            toast.remove();
