267 |     private fun processJson(jsonStr: String) {
268 |         if (!isReady) {
269 |             DebugLogger.log("TTS", "Not ready, queuing...")
270 |             Handler(Looper.getMainLooper()).postDelayed({ processJson(jsonStr) }, 2000)
271 |             return
272 |         }
273 |         try {
274 |             val root = JSONObject(jsonStr)
275 |             val solutions = root.optJSONArray("solutions") ?: return
276 |             if (solutions.length() == 0) return
277 |             
278 |             val count = solutions.length()
279 |             DebugLogger.log("TTS", "Processing $count solutions")
280 |             speakStatus("Processing $count solutions found in your image", false)
281 |             isProcessingBatch = true
282 |             pendingSyntheses.set(count)
283 |             val batchId = System.currentTimeMillis()
284 | 
285 |             for (i in 0 until solutions.length()) {
286 |                 val item = solutions.optJSONObject(i) ?: continue
287 |                 val type = item.optString("type", "sa")
288 |                 val rawNum = item.optString("number", i.toString())
289 |                 val number = rawNum.padStart(3, '0')
290 |                 
291 |                 // Collect all steps into one string
292 |                 val stepsArray = item.optJSONArray("steps")
293 |                 val stepsBuilder = StringBuilder()
294 |                 if (stepsArray != null) {
295 |                     for (j in 0 until stepsArray.length()) {
296 |                         stepsBuilder.append(stepsArray.optString(j)).append(". ")
297 |                     }
298 |                 }
299 |                 val allSteps = stepsBuilder.toString()
300 |                 val finalAnswer = item.optString("answer", "")
301 | 
302 |                 val typeName = when(type) {
303 |                     "wo" -> "Worked out solution"
304 |                     "tf" -> "True or False question"
305 |                     "mc" -> "Multiple Choice question"
306 |                     "ma" -> "Matching question"
307 |                     "fill" -> "Fill in the blank question"
308 |                     "sa" -> "Short Answer question"
309 |                     else -> "Question"
310 |                 }
311 |                 
312 |                 // Combine Steps + Answer for a complete reading
313 |                 val speech = if (type == "wo") {
314 |                     "$typeName number $rawNum. $allSteps In conclusion: $finalAnswer"
315 |                 } else {
316 |                     "$typeName number $rawNum. Answer: $finalAnswer"
317 |                 }
318 |                 val fileName = "${type}_${batchId}_${number}.wav"
319 |                 val file = File(audioFolder, fileName)
320 |                 val utteranceId = fileName
321 |                 
322 |                 tts.synthesizeToFile(speech, Bundle().apply { putString(TextToSpeech.Engine.KEY_PARAM_UTTERANCE_ID, utteranceId) }, file, utteranceId)
323 |             }
324 |         } catch (e: Exception) { DebugLogger.log("CRITICAL", "ProcessJson Error: ${e.message}") }
325 |     }
