567 |     private var isClaiming = false
568 |     private fun claimMediaFocus() {
569 |         if (isFocusHeld || isClaiming) return
570 |         isClaiming = true
571 | 
572 |         val am = getSystemService(Context.AUDIO_SERVICE) as android.media.AudioManager
573 |         
574 |         if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
575 |             val focusRequest = android.media.AudioFocusRequest.Builder(android.media.AudioManager.AUDIOFOCUS_GAIN)
576 |                 .setAudioAttributes(android.media.AudioAttributes.Builder()
577 |                     .setUsage(android.media.AudioAttributes.USAGE_MEDIA)
578 |                     .setContentType(android.media.AudioAttributes.CONTENT_TYPE_MUSIC)
579 |                     .build())
580 |                 .setOnAudioFocusChangeListener { focusChange ->
581 |                     if (focusChange == android.media.AudioManager.AUDIOFOCUS_LOSS || 
582 |                         focusChange == android.media.AudioManager.AUDIOFOCUS_LOSS_TRANSIENT) {
583 |                         isFocusHeld = false
584 |                         DebugLogger.log("SESSION", "Focus Surrendered")
585 |                         // Only retry once after 10 seconds to stop the spam loop
586 |                         handler.postDelayed({ isClaiming = false; claimMediaFocus() }, 10000)
587 |                     }
588 |                 }
589 |                 .build()
590 |             
591 |             val result = am.requestAudioFocus(focusRequest)
592 |             if (result == android.media.AudioManager.AUDIOFOCUS_REQUEST_GRANTED) {
593 |                 isFocusHeld = true
594 |                 DebugLogger.log("SESSION", "Focus Secured")
595 |                 mediaSession?.isActive = true
596 |                 startSilentLoop()
597 |             }
598 |         }
599 |         isClaiming = false
600 |     }
