646 |     private fun handleHeadsetCommand() {
647 |         val pm = getSystemService(Context.POWER_SERVICE) as PowerManager
648 |         val isScreenOff = !pm.isInteractive
649 |         
650 |         DebugLogger.log("HEADSET_EVENT", "--- HEADSET CLICK DETECTED ---")
651 |         DebugLogger.log("HEADSET_EVENT", "Interactive (Screen On): ${!isScreenOff}")
652 |         
653 |         vibrator?.vibrate(VibrationEffect.createOneShot(150, VibrationEffect.DEFAULT_AMPLITUDE))
654 |         DebugLogger.log("HEADSET_EVENT", "Vibration Triggered Successfully")
655 | 
656 |         val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
657 |         val actuallyActive = prefs.getBoolean("is_active", true)
658 |         
659 |         if (!actuallyActive) {
660 |             DebugLogger.log("HEADSET_EVENT", "Ignored: System is marked INACTIVE in SharedPreferences")
661 |             return
662 |         }
663 | 
664 |         if (isScreenOff) {
665 |             DebugLogger.log("HEADSET_EVENT", "SCREEN IS OFF -> Branching to wakeDevice()")
666 |             wakeDevice(pm)
667 |         } else {
668 |             DebugLogger.log("HEADSET_EVENT", "SCREEN IS ON -> Broadcasting SHUTTER signal")
669 |             val intent = Intent("com.universal.app.HEADSET_TRIGGER_SHUTTER")
670 |             sendBroadcast(intent)
671 |         }
672 |     }
