675 |     private fun wakeDevice(pm: PowerManager) {
676 |         DebugLogger.log("WAKE_TRACE", "Step 1: Entering wakeDevice() function")
677 |         
678 |         if (pm.isInteractive) {
679 |             DebugLogger.log("WAKE_TRACE", "Step 1.1: Cancelled - Device is already interactive")
680 |             return
681 |         }
682 | 
