// --- BUNDLER & PREVIEW ---
    let proxyHistory = [];
let proxyHistoryIndex = -1;

async function navigateProxy(forcedUrl = null, isReload = false) {
    const input = document.getElementById('browser-url');
    const url = forcedUrl || input.value.trim();
    if(!url) return;

    if (!isReload && url !== proxyHistory[proxyHistoryIndex]) {
        proxyHistory = proxyHistory.slice(0, proxyHistoryIndex + 1);
        proxyHistory.push(url);
        proxyHistoryIndex++;
    }

    const iframe = document.getElementById('preview-frame');
    iframe.srcdoc = '<div style="color:#666; font-family:sans-serif; text-align:center; padding:20px;">Proxying ' + url + '...</div>';

    try {
        const res = await fetch(CONFIG.funcUrl, {
            method: 'POST', headers: {'Content-Type': 'application/json'},
            body: apiBody({ action: 'proxy_web', url: url })
        });
        const html = await res.text();
        iframe.srcdoc = html;
        document.getElementById('preview-url-display').innerText = 'Browsing: ' + url;
        input.value = url;
    } catch(e) {
        iframe.srcdoc = '<div style="color:red; padding:20px;">Proxy Error: ' + e.message + '</div>';
    }
}

function proxyBack() {
    if (proxyHistoryIndex > 0) {
        proxyHistoryIndex--;
        navigateProxy(proxyHistory[proxyHistoryIndex], true);
    }
}

function proxyForward() {
    if (proxyHistoryIndex < proxyHistory.length - 1) {
        proxyHistoryIndex++;
        navigateProxy(proxyHistory[proxyHistoryIndex], true);
    }
}

