// --- BUNDLER & PREVIEW ---
function loadExternalUrl(forcedUrl = null) {
    const input = document.getElementById('browser-url');
    let url = forcedUrl || input.value.trim();
    if (!url) return;

    // Auto-prefix with https if protocol is missing
    if (!/^https?:\/\//i.test(url)) {
        url = 'https://' + url;
        input.value = url;
    }

    const iframe = document.getElementById('preview-frame');
    const display = document.getElementById('preview-url-display');

    // Revoke any existing local blob URLs to free memory
    if (window.PREVIEW_BLOB_URL) {
        URL.revokeObjectURL(window.PREVIEW_BLOB_URL);
        window.PREVIEW_BLOB_URL = null;
    }

    iframe.srcdoc = ''; // Clear srcdoc to allow src to take over
    iframe.src = url;
    display.innerText = 'External: ' + url;
    console.log("[Preview] Loading external URL:", url);
}

