function copyInsEntry(btn) {
    const row = btn.closest('.ins-row');
    // If network detail is open, copy the JSON inside it, otherwise the text of the row
    const details = row.querySelector('.ins-net-details.open');
    const text = details ? details.innerText.replace('Copy JSON', '') : row.innerText.replace('Copy', '');
    navigator.clipboard.writeText(text.trim()).then(() => {
        btn.innerText = 'Copied'; setTimeout(() => btn.innerText = 'Copy', 1000);
    });
}

